/**
* Уровни логирования
*/
export const enum LogLevel {
    /**
     * Все сообщения логируются с этим уровнем.
     */
    Trace = 1,

    /**
     * Сообщения с уровнем логирования debug и выше логируются с этим уровнем.
     */
    Debug = 2,

    /**
     * Сообщения с уровнем логирования info и выше логируются с этим уровнем.
     */
    Info = 3,

    /**
     * Сообщения с уровнем логирования warning и выше логируются с этим уровнем.
     */
    Warning = 4,

    /**
     * Только сообщения об ошибках логируются с этим уровнем.
     */
    Error = 5,

    /**
     * Никакие сообщения не логируются с этим уровнем.
     */
    Off = 10,
}

/**
* Представляет степень серьезности диагностики.
*/
export const enum DiagnosticSeverity {

    /**
     * Что-то, что не разрешено правилами.
     */
    Error = 0,

    /**
     * Что-то подозрительное, но разрешенное.
     */
    Warning = 1,

    /**
     * Что-то, о чем нужно сообщить, но не проблема.
     */
    Information = 2,

    /**
     * Что-то, чтобы подсказать о лучшем способе сделать это
     */
    Hint = 3,
    /**
     * Успешно выполненное действие или проверка
     */
    Success = 4,
}

/**
* Дополнительные метаданные о типе диагностики.
*/
export enum DiagnosticTag {
   /**
    * Неиспользуемый или ненужный элемент.
    *
    * Диагностики с этим тегом отображаются с затенением.
    */
   Unnecessary = 1,

   /**
    * Устаревший.
    *
    * Диагностики с этим тегом отображаются с зачеркиванием.
    */
   Deprecated = 2,
}
